INIT=$(curl -s -X POST http://localhost:8089/api/v1/negotiate/initiate -H "Content-Type: application/json" -d '{"header":{"workspace_id":"ws-1","mas_id":"mas-1"},"request_id":"i1","issues":["budget","timeline"],"options_per_issue":{"budget":["low","medium","high"],"timeline":["short","long"]},"participants":[{"id":"a","name":"Agent A","preferences":{"budget":{"low":0.9,"medium":0.5,"high":0.1},"timeline":{"short":0.8,"long":0.2}}},{"id":"b","name":"Agent B","preferences":{"budget":{"low":0.1,"medium":0.5,"high":0.9},"timeline":{"short":0.3,"long":0.7}}}]}') && echo "$INIT" | python3 -m json.tool && SID=$(echo "$INIT" | python3 -c "import sys,json; print(json.load(sys.stdin)['session_id'])") && echo "session_id=$SID"